
import { ValidateErrorEntity } from "ant-design-vue/es/form/interface";
import { Moment } from "moment";

import {
  defineComponent,
  onMounted,
  reactive,
  ref,
  toRefs,
  UnwrapRef,
  watch,
} from "vue";

import CheckBatchnumber from "./CheckBatchnumber.vue";
import { update_sample } from "../../../server/http/api/user";
import { getTime } from "../../../utils/setData";
import { useRoute, useRouter } from "vue-router";
import { getSampleGroupInfo } from "../../../server/http/api/user";
export default defineComponent({
  components: {
    CheckBatchnumber,
  },
  props: ["product_arr", "selectDetail"],
  setup(props, ctx) {
    const formRef = ref();
    const route = useRoute();
    const router = useRouter();
    const formState: UnwrapRef<any> = reactive({
      sampleName: "", //产品名称
      companyId: "", // 委托单位id
      specs: "", // 规格等级
      generation: "", // 代表批量
      sampleOrigin: "", // 样品产地
      sampleGroups: "", // 检测组数
      quantityPerGroup: "", // 每组数量
      manufacturer: "", // 生产厂家
      receivedDate: "", // 收样时间
      outward: [], // 样品外观
      inspector: "", // 验收员
      sampleRequirement: "", // 样品要求
      outwardDescribe: "",
      sampleQuantity: "", //样品修改
    });
    let data = reactive({
      num: 0,
    });

    onMounted(() => {
      // 初始化
      formState.quantityPerGroup = 1;
      formState.sampleGroups = 1;
      // let sample: any = sessionStorage.getItem("sample");
      // let willUpdateData = JSON.parse(sample);
      let insertFlag: any = route.params.insertFlag;
      getSampleGroupInfo(insertFlag).then((res: any) => {
        if (res.data.code === 200) {
          //console.log(res.data.data);

          let willUpdateData: any = res.data.data;
          //console.log("willUpdateData", willUpdateData);
          let arr = willUpdateData.outward.split("、");
          arr.splice(willUpdateData.outward.split("、").length - 1, 1);

          Object.assign(willUpdateData, {
            outward: arr,
            outwardDescribe:
              willUpdateData.outward.split("、")[
                willUpdateData.outward.split("、").length - 1
              ],
          });
          Object.assign(formState, willUpdateData);
        }
      });
    });

    watch(
      [() => formState.sampleGroups, () => formState.quantityPerGroup],
      (newval, o) => {
        //console.log(newval);
        data.num = newval[0] * newval[1];
        //console.log(data.num);
      }
    );
    const rules = {
      sampleName: [
        {
          required: true,
          message: "必须填写产品名称",
        },
      ],
      companyId: [
        {
          required: true,
          message: "必须填写委托单位",
        },
      ],
      specs: [
        {
          required: true,
          message: "规格等级必填",
        },
      ],
    };
    const onSubmit = () => {
      formRef.value
        .validate()
        .then(() => {
          if (typeof formState.receivedDate !== "string") {
            Object.assign(formState, {
              receivedDate: getTime(formState.receivedDate),
            });
          }

          update_sample(formState).then((res: any) => {
            //console.log(res);
            router.go(-1);
            localStorage.removeItem("sample");
          });
        })
        .catch((error: ValidateErrorEntity<any>) => {
          //console.log("error", error);
        });
    };
    const resetForm = () => {
      formRef.value.resetFields();
    };
    return {
      formRef,
      labelCol: { style: { width: "150px" } },
      wrapperCol: { span: 14 },
      other: "",
      formState,
      rules,
      ...toRefs(data),
      onSubmit,
      resetForm,
    };
  },
});
