
import ReturnTitle from "@/components/OS_component/ReturnTitle.vue";
import { defineComponent, onMounted, reactive, toRef, toRefs } from "vue";
import { useRoute } from "vue-router";
import SampleFrom from "../../../../components/ATestdetection/UpdateSample/SampleFrom.vue";
import {
  get_sample_product_name,
  get_select_value,
} from "../../../../server/http/api/user";
export default defineComponent({
  name: "SampleUpdate",
  components: {
    SampleFrom,
    ReturnTitle,
  },
  setup() {
    const route = useRoute();

    let data = reactive({
      product_arr: [],
      selectDetail: [],
    });
    // 查询产品检测项
    get_sample_product_name().then((res: any) => {
      if (res.data.code === 200) {
        data.product_arr = res.data.data;
      }
    });
    // 查询委托单位 、样品外观
    get_select_value().then((res: any) => {
      if (res.data.code === 200) {
        data.selectDetail = res.data.data;
      }
    });

    return {
      ...toRefs(data),
    };
  },
});
